Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: inject a fake handler into HttpClient
    private static (DataFetcher fetcher, MockHandler handler) CreateSut()
    {
        var handler = new MockHandler();
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var (fetcher, handler) = CreateSut();
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var (fetcher, handler) = CreateSut();
        handler.Response = new HttpResponseMessage(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        var (fetcher, handler) = CreateSut();
        // Handler delays long enough for cancellation to fire
        handler.Delay = TimeSpan.FromSeconds(30);
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK);

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net — fail if test hangs
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var (fetcher, handler) = CreateSut();
        handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast")
        };

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Minimal fake handler — no external mocking library needed
    private class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            return Response;
        }
    }
}
```

**Key points:**

- **`HttpMessageHandler` subclass** — lets you control responses without hitting the network and without mocking `HttpClient` directly (which is notoriously hard).
- **`[Timeout(ms)]`** — MSTest's built-in safety net; fails the test if it hangs instead of blocking CI forever.
- **`CancellationTokenSource` with a timeout** — tests that your code actually forwards the token. The handler's `Task.Delay` respects the token, so cancellation fires quickly.
- **`async Task` test methods** — MSTest natively awaits them; never use `async void`.
